 {"id":"bd-2q5d","title":"kqueue reactor: macOS native I/O multiplexing","description":"# kqueue Reactor Implementation (macOS)

## Overview
Implements the Reactor trait using kqueue, the native I/O multiplexing mechanism
on macOS (and other BSDs).

## Background
kqueue is the BSD/macOS equivalent of Linux epoll. It uses kevents to describe
changes and receive notifications. Key features:
- Edge-triggered or level-triggered modes
- Supports files, sockets, timers, signals, processes
- Efficient for large numbers of descriptors

## Design

### KqueueReactor Structure
```rust
pub struct KqueueReactor {
    /// kqueue file descriptor
    kq: RawFd,
    /// Pending changes to submit
    changes: Mutex<Vec<kevent>>,
    /// Wake eventfd for cross-thread wakeup
    wake_pipe: (RawFd, RawFd),
}

impl KqueueReactor {
    pub fn new() -> io::Result<Self> {
        let kq = unsafe { libc::kqueue() };
        if kq < 0 {
            return Err(io::Error::last_os_error());
        }

        // Create pipe for wakeup
        let mut fds = [0; 2];
        if unsafe { libc::pipe(fds.as_mut_ptr()) } < 0 {
            return Err(io::Error::last_os_error());
        }

        // Register wake pipe
        // ...

        Ok(Self { kq, changes: Mutex::new(Vec::new()), wake_pipe: (fds[0], fds[1]) })
    }
}
```

### Reactor Implementation
```rust
impl Reactor for KqueueReactor {
    fn register(&self, fd: RawFd, token: usize, interest: Interest) -> io::Result<()> {
        let mut changes = self.changes.lock().unwrap();

        if interest.readable {
            changes.push(kevent {
                ident: fd as usize,
                filter: libc::EVFILT_READ,
                flags: libc::EV_ADD | libc::EV_CLEAR,
                fflags: 0,
                data: 0,
                udata: token as *mut _,
            });
        }

        if interest.writable {
            changes.push(kevent {
                ident: fd as usize,
                filter: libc::EVFILT_WRITE,
                flags: libc::EV_ADD | libc::EV_CLEAR,
                fflags: 0,
                data: 0,
                udata: token as *mut _,
            });
        }

        Ok(())
    }

    fn poll(&self, events: &mut Events, timeout: Option<Duration>) -> io::Result<usize> {
        let changes = std::mem::take(&mut *self.changes.lock().unwrap());

        let timeout_spec = timeout.map(|d| libc::timespec {
            tv_sec: d.as_secs() as i64,
            tv_nsec: d.subsec_nanos() as i64,
        });

        let mut kevents = vec![unsafe { std::mem::zeroed() }; events.capacity];

        let n = unsafe {
            libc::kevent(
                self.kq,
                changes.as_ptr(),
                changes.len() as i32,
                kevents.as_mut_ptr(),
                kevents.len() as i32,
                timeout_spec.as_ref().map_or(std::ptr::null(), |t| t),
            )
        };

        if n < 0 {
            return Err(io::Error::last_os_error());
        }

        // Convert kevents to Events
        for i in 0..n as usize {
            let kev = &kevents[i];
            let ready = Interest {
                readable: kev.filter == libc::EVFILT_READ,
                writable: kev.filter == libc::EVFILT_WRITE,
                error: kev.flags & libc::EV_ERROR != 0,
            };
            events.push(Event { token: kev.udata as usize, ready });
        }

        Ok(n as usize)
    }

    fn wake(&self) -> io::Result<()> {
        let buf = [1u8];
        let _ = unsafe { libc::write(self.wake_pipe.1, buf.as_ptr() as *const _, 1) };
        Ok(())
    }
}
```

